#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct{
	double r;
	double i;
} RSComplex;

typedef struct{
	RSComplex MP_EA;
	RSComplex MP_RT;
	RSComplex MP_RA;
	RSComplex MP_RF;
	short int l_value;
} Pole;

typedef struct{
	double T;
	double A;
	double F;
	int start;
	int end;
} Window;

typedef struct{
	int nthreads;
	int n_nuclides;
	int lookups;
	int HM;
